using System;
using System.IO;
using System.Runtime.CompilerServices;
using HarfBuzzSharp;

const int DataSize = 64 * 1024;
const int Iterations = 200;
int corruptionCount = 0;
int crashCount = 0;
byte[] referenceData = new byte[DataSize];
for (int i = 0; i < DataSize; i++)
    referenceData[i] = (byte)(i % 251);

for (int iter = 0; iter < Iterations; iter++)
{
    try
    {
        using var blob = CreateBlobFromStream(referenceData);
        FragmentHeap();
        GC.Collect(2, GCCollectionMode.Forced, blocking: true, compacting: true);
        GC.WaitForPendingFinalizers();
        GC.Collect(2, GCCollectionMode.Forced, blocking: true, compacting: true);
        var span = blob.AsSpan();
        for (int i = 0; i < span.Length; i++)
        {
            if (span[i] != referenceData[i]) { corruptionCount++; break; }
        }
    }
    catch { crashCount++; }
}
Console.WriteLine($"Results: {Iterations} iterations, {corruptionCount} corruptions, {crashCount} crashes");
if (corruptionCount > 0 || crashCount > 0) Environment.Exit(1);

[MethodImpl(MethodImplOptions.NoInlining)]
static Blob CreateBlobFromStream(byte[] data) { using var s = new MemoryStream(data); return Blob.FromStream(s); }

[MethodImpl(MethodImplOptions.NoInlining)]
static void FragmentHeap() { var r = new Random(42); var a = new object[1000]; for (int i=0;i<1000;i++) a[i]=new byte[r.Next(100,10000)]; for (int i=0;i<1000;i+=2) a[i]=null; for (int i=0;i<500;i++) _=new byte[r.Next(50,5000)]; }
